using System.Collections;
using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// "Humor"/estado de reação actual do NPC perante o player (Etapa 7) — definido
/// por Action_SetReactionState e lido por Condition_NpcReactionState. Permite
/// condicionar eventos ao "humor" do NPC (ex: um guarda só ataca por Touch se
/// estiver Hostile) e dar feedback visual (Animator/sprite) sobre esse humor.
/// </summary>
public enum NpcReactionState
{
    Idle,
    Alert,
    Friendly,
    Hostile,
    Fleeing,
    Surprised,
    Sleeping
}

/// <summary>Associa um sprite a um estado de reação, para SetReactionState trocar o visual do NPC.</summary>
[System.Serializable]
public class NpcReactionSprite
{
    public NpcReactionState state;
    public Sprite sprite;
}

/// <summary>
/// Controlador principal de um NPC: gere a lista de eventos configuráveis no
/// Inspector, detecta o player, decide qual evento disparar (Auto/Touch/Button)
/// consoante prioridade, condições e alcance, e corre as suas ações em sequência.
/// </summary>
public class NpcController : MonoBehaviour
{
    [Header("Identidade")]
    [Tooltip("Nome mostrado no balão de diálogo quando este NPC fala (Speaker = Self, ou quando outro NPC o referencia como 'Outro NPC'). Se vazio, usa o nome do GameObject.")]
    [SerializeField] private string displayName;

    [Tooltip("Identificador único deste NPC na cena (opcional, Etapa 8). Permite que ações/condições (deste ou de outros NPCs) o referenciem por ID — ex: 'olhar para', 'mover para um NPC' — em vez de arrastar uma referência directa. Deve ser único; duplicados geram um aviso no Console.")]
    [SerializeField] private string npcId;

    [Header("Eventos")]
    public List<NpcEvent> events = new List<NpcEvent>();

    [Header("Interação")]
    [Tooltip("Alcance usado por eventos Auto/Button cujo 'Interaction Range' seja <= 0.")]
    public float defaultInteractionRange = 1.5f;

    [Header("Referências (auto-detectadas se vazias)")]
    [SerializeField] private Transform player;
    [SerializeField] private SpriteRenderer spriteRenderer;
    [SerializeField] private NpcMovement movement;

    [Header("Diálogo / Escolhas (Etapa 2 - opcional)")]
    [Tooltip("Componente que implementa INpcDialogueDisplay. Se vazio, Action_Dialogue usa Debug.Log.")]
    [SerializeField] private MonoBehaviour dialogueDisplay;

    [Tooltip("Componente que implementa INpcChoiceMenu. Necessário para Action_ShowChoices.")]
    [SerializeField] private MonoBehaviour choiceMenu;

    [Header("Visibilidade Condicional (Etapa 7)")]
    [Tooltip("Se vazia, o NPC está sempre visível/activo (comportamento por omissão). Caso contrário, estas condições são avaliadas continuamente: enquanto TODAS forem verdadeiras o NPC fica visível e activo, caso contrário fica escondido (sprite desligado, colliders de trigger desligados, NpcMovement suspenso e nenhum evento é avaliado). Não combinar com Action_SetNpcVisible no mesmo NPC — a avaliação automática sobrepõe-se à acção no frame seguinte.")]
    [SerializeReference] public List<NpcCondition> visibilityConditions = new List<NpcCondition>();

    [Header("Estados de Reação (Etapa 7)")]
    [Tooltip("Auto-detectado se vazio. Recebe (int)ReactionState no parâmetro abaixo, se definido.")]
    [SerializeField] private Animator animator;

    [Tooltip("Nome do parâmetro Int do Animator actualizado por SetReactionState. Vazio = não actualiza o Animator.")]
    [SerializeField] private string reactionStateAnimParam = "ReactionState";

    [Tooltip("Sprite a usar para cada estado de reação (opcional). Se não houver entrada para o estado, o sprite não é alterado.")]
    [SerializeField] private List<NpcReactionSprite> reactionSprites = new List<NpcReactionSprite>();

    [Header("Variáveis Locais (Etapa 8)")]
    [Tooltip("Variáveis próprias deste NPC (bool/int/float/string). Lidas e escritas por Action_Set*Variable / Condition_*Variable com 'scope = Local' — só os eventos deste NPC as veem. Para variáveis partilhadas por todo o jogo usa 'scope = Global' (ver GameVariables).")]
    [SerializeField] private List<GameVariable> localVariables = new List<GameVariable>();

    /// <summary>Regista todos os NpcController activos pelo seu "npcId" (ver NpcId / FindById).</summary>
    private static readonly Dictionary<string, NpcController> _registry = new Dictionary<string, NpcController>();

    private PlayerInputRouter _playerInput;
    private bool _isRunningEvent;
    private NpcEvent _activeEvent;
    private NpcEvent _pendingButtonEvent;

    private bool _visible = true;
    private NpcReactionState _reactionState = NpcReactionState.Idle;
    private int _reactionStateAnimHash = -1;
    private Coroutine _opacityRoutine;

    /// <summary>Nome mostrado no balão de diálogo. Se "displayName" estiver vazio, usa o nome do GameObject.</summary>
    public string DisplayName => string.IsNullOrEmpty(displayName) ? name : displayName;

    /// <summary>Identificador único deste NPC (ver campo "Npc Id" no Inspector). Pode estar vazio.</summary>
    public string NpcId => npcId;

    public Transform Player => player;
    public NpcMovement Movement => movement;
    public INpcDialogueDisplay DialogueDisplay => dialogueDisplay as INpcDialogueDisplay;
    public INpcChoiceMenu ChoiceMenu => choiceMenu as INpcChoiceMenu;
    public NpcEvent ActiveEvent => _activeEvent;

    /// <summary>True enquanto o NPC está visível e activo (ver "visibilityConditions" e SetVisible).</summary>
    public bool IsVisible => _visible;

    /// <summary>Estado de reação actual (ver SetReactionState / Action_SetReactionState).</summary>
    public NpcReactionState ReactionState => _reactionState;

    private void Awake()
    {
        foreach (var ev in events)
            if (ev != null) ev.isActive = ev.startActive;

        if (player == null)
        {
            var playerGo = GameObject.FindGameObjectWithTag("Player");
            if (playerGo != null) player = playerGo.transform;
        }

        if (player != null)
            _playerInput = player.GetComponent<PlayerInputRouter>();

        if (spriteRenderer == null)
            spriteRenderer = GetComponent<SpriteRenderer>();

        if (movement == null)
            movement = GetComponent<NpcMovement>();

        if (animator == null)
            animator = GetComponent<Animator>();

        if (animator != null && !string.IsNullOrEmpty(reactionStateAnimParam))
            _reactionStateAnimHash = Animator.StringToHash(reactionStateAnimParam);

        // Visibilidade inicial: se houver condições de visibilidade e não se cumprirem
        // já no arranque, o NPC começa escondido (ex: um NPC que só aparece depois de
        // um certo progresso, colocado na cena desde o início).
        if (visibilityConditions != null && visibilityConditions.Count > 0 && !EvaluateConditionList(visibilityConditions))
            ApplyVisibility(false);
    }

    private void OnEnable()
    {
        if (_playerInput != null)
            _playerInput.InteractPressed += HandleInteractPressed;

        if (!string.IsNullOrEmpty(npcId))
            _registry[npcId] = this;
    }

    private void OnDisable()
    {
        if (_playerInput != null)
            _playerInput.InteractPressed -= HandleInteractPressed;

        if (!string.IsNullOrEmpty(npcId) && _registry.TryGetValue(npcId, out var registered) && registered == this)
            _registry.Remove(npcId);
    }

    /// <summary>Procura, entre os NPCs activos, aquele cujo "Npc Id" seja "id". Devolve null se vazio ou não encontrado.</summary>
    public static NpcController FindById(string id)
    {
        if (string.IsNullOrEmpty(id)) return null;
        return _registry.TryGetValue(id, out var npc) ? npc : null;
    }

    private void Update()
    {
        if (_isRunningEvent) return;

        UpdateVisibility();

        if (!_visible)
        {
            _pendingButtonEvent = null;
            return;
        }

        // Auto: dispara assim que o player está no alcance e as condições são cumpridas.
        var autoEvent = FindBestEvent(NpcInteractionType.Auto);
        if (autoEvent != null)
        {
            TriggerEvent(autoEvent);
            return;
        }

        // Button: guarda o melhor evento elegível para o player disparar com o botão de interação.
        _pendingButtonEvent = FindBestEvent(NpcInteractionType.Button);
    }

    private void HandleInteractPressed()
    {
        if (_isRunningEvent) return;
        if (_pendingButtonEvent == null) return;

        // Mitigação do conflito de InteractPressed (pedido "InteractionManager"):
        // se outro sistema já reagiu a este toque (ex.: diálogo activo), não
        // disparamos também o evento deste NPC.
        if (_playerInput != null && _playerInput.InteractConsumed) return;

        TriggerEvent(_pendingButtonEvent);

        if (_playerInput != null) _playerInput.InteractConsumed = true;
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        HandleTouch(other.transform);
    }

    private void OnCollisionEnter2D(Collision2D collision)
    {
        HandleTouch(collision.transform);
    }

    private void HandleTouch(Transform other)
    {
        if (_isRunningEvent) return;
        if (player == null || other != player) return;

        var touchEvent = FindBestEvent(NpcInteractionType.Touch);
        if (touchEvent != null)
            TriggerEvent(touchEvent);
    }

    /// <summary>Devolve o evento activo, deste tipo de interação, com maior prioridade cujo alcance e condições sejam cumpridos.</summary>
    private NpcEvent FindBestEvent(NpcInteractionType type)
    {
        NpcEvent best = null;

        foreach (var ev in events)
        {
            if (ev == null || !ev.isActive) continue;
            if (ev.interactionType != type) continue;
            if (best != null && ev.priority <= best.priority) continue;

            if ((type == NpcInteractionType.Auto || type == NpcInteractionType.Button) && !IsPlayerInRange(ev))
                continue;

            if (!EvaluateConditions(ev)) continue;

            best = ev;
        }

        return best;
    }

    private bool EvaluateConditions(NpcEvent ev)
    {
        return EvaluateConditionList(ev.conditions);
    }

    /// <summary>Avalia uma lista de condições (AND lógico). Lista vazia ou nula = verdadeiro.</summary>
    private bool EvaluateConditionList(List<NpcCondition> conditions)
    {
        if (conditions == null) return true;

        foreach (var condition in conditions)
        {
            if (condition == null) continue;
            if (!condition.Evaluate(this)) return false;
        }

        return true;
    }

    private bool IsPlayerInRange(NpcEvent ev)
    {
        if (player == null) return false;

        float range = ev.interactionRange > 0f ? ev.interactionRange : defaultInteractionRange;
        return Vector2.Distance(player.position, transform.position) <= range;
    }

    private void TriggerEvent(NpcEvent ev)
    {
        StartCoroutine(RunEvent(ev));
    }

    /// <summary>
    /// Dispara imediatamente o evento cujo <see cref="NpcEvent.eventId"/> seja
    /// "eventId", sem aguardar input do player nem verificar condições.
    /// Útil para sistemas externos (ex: <see cref="ChallengeManager"/> ao
    /// conceder uma recompensa com cena de NPC).
    /// Se o NPC já estiver a correr um evento, o novo é ignorado; o chamador
    /// deve aguardar ou usar <see cref="ActivateEventById"/> para que o evento
    /// dispare naturalmente no próximo ciclo de Update.
    /// </summary>
    public void TriggerEventById(string eventId)
    {
        if (_isRunningEvent) return;
        var ev = FindEventById(eventId);
        if (ev != null) TriggerEvent(ev);
    }

    private IEnumerator RunEvent(NpcEvent ev)
    {
        _isRunningEvent = true;
        _activeEvent = ev;

        if (ev.overrideSprite != null && spriteRenderer != null)
            spriteRenderer.sprite = ev.overrideSprite;

        if (ev.actions != null)
        {
            foreach (var action in ev.actions)
            {
                if (action == null) continue;
                yield return action.Execute(this);
            }
        }

        if (ev.deactivateOnComplete)
            ev.isActive = false;

        if (!string.IsNullOrEmpty(ev.activateEventIdOnComplete))
            ActivateEventById(ev.activateEventIdOnComplete);

        _activeEvent = null;
        _isRunningEvent = false;
    }

    /// <summary>Procura um evento deste NPC pelo seu eventId.</summary>
    public NpcEvent FindEventById(string eventId)
    {
        if (string.IsNullOrEmpty(eventId)) return null;

        foreach (var ev in events)
            if (ev != null && ev.eventId == eventId) return ev;

        return null;
    }

    /// <summary>
    /// Activa um evento pelo seu eventId (define isActive = true). Não dispara
    /// o evento de imediato — o disparo natural acontece no próximo Update/Touch/Button,
    /// evitando reentrância enquanto outra ação ainda está a correr.
    /// </summary>
    public void ActivateEventById(string eventId)
    {
        var ev = FindEventById(eventId);
        if (ev != null) ev.isActive = true;
    }

    /// <summary>Desactiva um evento pelo seu eventId (define isActive = false).</summary>
    public void DeactivateEventById(string eventId)
    {
        var ev = FindEventById(eventId);
        if (ev != null) ev.isActive = false;
    }

    /// <summary>Re-avalia "visibilityConditions" e aplica a visibilidade se tiver mudado. Sem efeito se a lista estiver vazia.</summary>
    private void UpdateVisibility()
    {
        if (visibilityConditions == null || visibilityConditions.Count == 0) return;

        bool shouldBeVisible = EvaluateConditionList(visibilityConditions);
        if (shouldBeVisible == _visible) return;

        ApplyVisibility(shouldBeVisible);
    }

    /// <summary>
    /// Mostra ou escode este NPC explicitamente (Action_SetNpcVisible). Não usar
    /// no mesmo NPC que tenha "visibilityConditions" preenchida — a avaliação
    /// automática sobrepõe-se a esta chamada no frame seguinte.
    /// </summary>
    public void SetVisible(bool visible)
    {
        if (visible == _visible) return;
        ApplyVisibility(visible);
    }

    /// <summary>
    /// Aplica o estado de visibilidade: liga/desliga o SpriteRenderer, os
    /// colliders de trigger (interação/Touch) e o NpcMovement. Colliders
    /// sólidos (não-trigger, ex: chão) não são tocados, para o NPC não cair
    /// ou "perder" física enquanto está escondido.
    /// </summary>
    private void ApplyVisibility(bool visible)
    {
        _visible = visible;

        if (spriteRenderer != null)
            spriteRenderer.enabled = visible;

        foreach (var col in GetComponents<Collider2D>())
        {
            if (col.isTrigger) col.enabled = visible;
        }

        if (movement != null)
            movement.enabled = visible;
    }

    /// <summary>
    /// Muda a opacidade (alfa do SpriteRenderer) deste NPC — Action_SetNpcOpacity.
    /// Se "duration" for 0, aplica de imediato; caso contrário interpola ao
    /// longo de "duration" segundos. Permite fazer o NPC desaparecer
    /// gradualmente (targetAlpha = 0), ficar translúcido (ex: 0.5) ou voltar a
    /// ficar opaco (1), sem afectar colliders/movimento (para isso ver
    /// SetVisible/Action_SetNpcVisible). Cancela qualquer transição de
    /// opacidade em curso. Devolve a Coroutine iniciada (ou null se aplicada
    /// de imediato ou se não houver SpriteRenderer), para quem quiser aguardar
    /// a conclusão.
    /// </summary>
    public Coroutine SetOpacity(float targetAlpha, float duration)
    {
        if (spriteRenderer == null) return null;

        if (_opacityRoutine != null)
        {
            StopCoroutine(_opacityRoutine);
            _opacityRoutine = null;
        }

        targetAlpha = Mathf.Clamp01(targetAlpha);

        if (duration <= 0f)
        {
            var c = spriteRenderer.color;
            c.a = targetAlpha;
            spriteRenderer.color = c;
            return null;
        }

        _opacityRoutine = StartCoroutine(FadeOpacityRoutine(targetAlpha, duration));
        return _opacityRoutine;
    }

    private IEnumerator FadeOpacityRoutine(float targetAlpha, float duration)
    {
        float startAlpha = spriteRenderer.color.a;
        float t = 0f;

        while (t < duration)
        {
            t += Time.deltaTime;
            var c = spriteRenderer.color;
            c.a = Mathf.Lerp(startAlpha, targetAlpha, Mathf.Clamp01(t / duration));
            spriteRenderer.color = c;
            yield return null;
        }

        var finalColor = spriteRenderer.color;
        finalColor.a = targetAlpha;
        spriteRenderer.color = finalColor;

        _opacityRoutine = null;
    }

    /// <summary>
    /// Define o estado de reação actual (Action_SetReactionState). Actualiza o
    /// parâmetro Int do Animator (se configurado) e troca o sprite caso haja
    /// uma entrada em "reactionSprites" para este estado.
    /// </summary>
    public void SetReactionState(NpcReactionState state)
    {
        _reactionState = state;

        if (animator != null && _reactionStateAnimHash != -1)
            animator.SetInteger(_reactionStateAnimHash, (int)state);

        if (spriteRenderer != null && reactionSprites != null)
        {
            foreach (var entry in reactionSprites)
            {
                if (entry != null && entry.state == state && entry.sprite != null)
                {
                    spriteRenderer.sprite = entry.sprite;
                    break;
                }
            }
        }
    }

    private void OnValidate()
    {
        if (dialogueDisplay != null && !(dialogueDisplay is INpcDialogueDisplay))
        {
            Debug.LogWarning($"[{name}] '{dialogueDisplay.GetType().Name}' não implementa INpcDialogueDisplay. A referência foi removida.", this);
            dialogueDisplay = null;
        }

        if (choiceMenu != null && !(choiceMenu is INpcChoiceMenu))
        {
            Debug.LogWarning($"[{name}] '{choiceMenu.GetType().Name}' não implementa INpcChoiceMenu. A referência foi removida.", this);
            choiceMenu = null;
        }

        if (!string.IsNullOrEmpty(npcId))
        {
            foreach (var other in FindObjectsOfType<NpcController>())
            {
                if (other == this || other.npcId != npcId) continue;
                Debug.LogWarning($"[{name}] Npc Id '{npcId}' já está em uso por '{other.name}'. Escolhe um ID único.", this);
                break;
            }
        }
    }

    // ---------------- Variáveis Locais (Etapa 8) ----------------

    public bool GetLocalBool(string varName, bool defaultValue = false) => GameVariableListUtil.GetBool(localVariables, varName, defaultValue);
    public int GetLocalInt(string varName, int defaultValue = 0) => GameVariableListUtil.GetInt(localVariables, varName, defaultValue);
    public float GetLocalFloat(string varName, float defaultValue = 0f) => GameVariableListUtil.GetFloat(localVariables, varName, defaultValue);
    public string GetLocalString(string varName, string defaultValue = "") => GameVariableListUtil.GetString(localVariables, varName, defaultValue);

    public void SetLocalBool(string varName, bool value) => GameVariableListUtil.SetBool(localVariables, varName, value);
    public void SetLocalInt(string varName, int value) => GameVariableListUtil.SetInt(localVariables, varName, value);
    public void SetLocalFloat(string varName, float value) => GameVariableListUtil.SetFloat(localVariables, varName, value);
    public void SetLocalString(string varName, string value) => GameVariableListUtil.SetString(localVariables, varName, value);

    private void OnDrawGizmosSelected()
    {
        Gizmos.color = Color.cyan;

        foreach (var ev in events)
        {
            if (ev == null) continue;
            if (ev.interactionType != NpcInteractionType.Auto && ev.interactionType != NpcInteractionType.Button) continue;

            float range = ev.interactionRange > 0f ? ev.interactionRange : defaultInteractionRange;
            Gizmos.DrawWireSphere(transform.position, range);
        }
    }
}
